'use strict';

/*
  Shared message-type constants for the postMessage bridge between a host
  extension page (main.html / settings.html) and its single sandboxed iframe
  (sandbox.html). Imported by both sides so the protocol can't drift.

  MV3 forbids 'unsafe-eval' in extension pages, so all plugin code is eval'd
  inside the sandbox iframe (whose CSP still permits it). There is ONE iframe per
  page hosting ALL plugins in a shared realm — exactly like the old on-page
  engine. View rendering and the activity stack live entirely inside the iframe;
  only things that need the host's origin/privileges cross this bridge:
  network, persistence, chrome.*, button actions, toasts, and the fade overlay.

  Every message is an object `{type, ...payload}`. Round-trip requests carry a
  monotonic `reqId` that the response echoes.
*/

// Sandbox -> host
const SANDBOX_READY = 'sandbox-ready';   // iframe loaded, ready to be seeded/run
const REGISTER_ACTION = 'register-action'; // {displayName, actionPathname} record an action:// URI
const ACTIVITY_STATE = 'activity-state'; // {title, canGoBack} nav title + back-button state changed
const NET_FETCH = 'net-fetch';           // {reqId, url, dataType, options} cross-origin fetch by host
const CACHE_GET = 'cache-get';           // {reqId, key}
const CACHE_SET = 'cache-set';           // {key, value}
const OPEN_TAB = 'open-tab';             // {url, active}
const TOAST = 'toast';                   // {text} show a Materialize toast on the host page
const FADE_CONFIG = 'fade-config';       // {delay, background, invert} set up the host fade overlay
const FADE_ACTIVITY = 'fade-activity';   // {} user activity seen inside the iframe; reset the fade timer
const FADE_FEATURED = 'fade-featured';   // {html} content to mirror on top of the overlay
const RUN_DONE = 'run-done';             // {plugin, view} a requested view finished executing

// Host -> sandbox
const SEED = 'seed';                     // {themes, currentThemeIdx, themeCss} one-time
const RUN = 'run';                       // {plugin, view} register plugin then inject html/css + eval js
const ACTION_INVOKE = 'action-invoke';   // {uri} an action:// URI fired on the host
const POP_REQUEST = 'pop-request';       // {} the host back button was pressed
const NET_RESULT = 'net-result';         // {reqId, ok, status, body}
const CACHE_RESULT = 'cache-result';     // {reqId, value}

// Build the action:// URI for a plugin action. Must be computed identically on
// both sides of the bridge so the host and sandbox agree on the key.
const buildActionUri = (pluginName, actionPathname) =>
  `action://${`${pluginName}/${actionPathname}`.split('/').map(encodeURIComponent).join('/')}`;

export {
  buildActionUri,
  SANDBOX_READY,
  REGISTER_ACTION,
  ACTIVITY_STATE,
  NET_FETCH,
  CACHE_GET,
  CACHE_SET,
  OPEN_TAB,
  TOAST,
  FADE_CONFIG,
  FADE_ACTIVITY,
  FADE_FEATURED,
  RUN_DONE,
  SEED,
  RUN,
  ACTION_INVOKE,
  POP_REQUEST,
  NET_RESULT,
  CACHE_RESULT
};
